// validation.js — reusable input-validation helpers

'use strict';

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// --- individual field validators -------------------------------------------

/**
 * Validate a user `id` coming from a URL parameter.
 * Express gives us strings from req.params, so we coerce and then check.
 *
 * @param {string|number} value
 * @param {string}        fieldName  Label used in the error message (default "id")
 * @returns {string|null}  Error string, or null when valid
 */
function validateId(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

/**
 * Validate a `name` field.
 *
 * @param {*}      value
 * @param {string} fieldName  Label used in the error message (default "name")
 * @returns {string|null}
 */
function validateName(value, fieldName = 'name') {
  if (value === undefined || value === null) {
    return `${fieldName} is required`;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return `${fieldName} must be at least 1 character`;
  }
  if (trimmed.length > 100) {
    return `${fieldName} must be at most 100 characters`;
  }
  return null;
}

/**
 * Validate an `email` field.
 *
 * @param {*}      value
 * @param {string} fieldName  Label used in the error message (default "email")
 * @returns {string|null}
 */
function validateEmail(value, fieldName = 'email') {
  if (value === undefined || value === null) {
    return `${fieldName} is required`;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > 254) {
    return `${fieldName} must be at most 254 characters`;
  }
  if (!EMAIL_RE.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

// --- composite validators ---------------------------------------------------

/**
 * Validate all fields required to CREATE a user (POST /users).
 * Both `name` and `email` are required.
 *
 * @param {object} body  req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [];

  const nameErr = validateName(body.name);
  if (nameErr) errors.push(nameErr);

  const emailErr = validateEmail(body.email);
  if (emailErr) errors.push(emailErr);

  return { valid: errors.length === 0, errors };
}

/**
 * Validate fields for UPDATE a user (PUT /users/:id).
 * At least one of `name` or `email` must be supplied; any supplied field is
 * fully validated.
 *
 * @param {object} body  req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(body) {
  const errors = [];

  if (body.name === undefined && body.email === undefined) {
    errors.push('at least one field (name, email) must be provided for update');
    return { valid: false, errors };
  }

  if (body.name !== undefined) {
    const nameErr = validateName(body.name);
    if (nameErr) errors.push(nameErr);
  }

  if (body.email !== undefined) {
    const emailErr = validateEmail(body.email);
    if (emailErr) errors.push(emailErr);
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate a numeric `:id` URL parameter.
 *
 * @param {string} idParam  req.params.id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserIdParam(idParam) {
  const errors = [];
  const idErr = validateId(idParam);
  if (idErr) errors.push(idErr);
  return { valid: errors.length === 0, errors };
}

// --- Express middleware factory ---------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` against the request
 * and, when validation fails, immediately responds with a 400 that lists
 * every failed rule.
 *
 * Usage:
 *   app.post('/users', validate(req => validateCreateUser(req.body)), handler)
 *
 * @param {function(req): { valid: boolean, errors: string[] }} validatorFn
 * @returns {function}  Express middleware
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const { valid, errors } = validatorFn(req);
    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validateUserIdParam,
  validate,
};

