/**
 * Validation helper module.
 * Each validator returns an array of error message strings.
 * An empty array means the input is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` from a route parameter.
 * Must be a positive integer string (e.g. "42").
 *
 * @param {string} value - Raw route param value.
 * @returns {string[]} Array of validation error messages.
 */
function validateId(value) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push('id is required');
    return errors;
  }

  if (!/^\d+$/.test(String(value)) || Number(value) <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field from a request body.
 * Must be a non-empty string between 1 and 100 characters.
 *
 * @param {*} value - Raw body value.
 * @param {boolean} [required=true] - Whether the field is required.
 * @returns {string[]} Array of validation error messages.
 */
function validateName(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < 1) {
    errors.push('name must be at least 1 character long');
  } else if (trimmed.length > 100) {
    errors.push('name must be at most 100 characters long');
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 * Must be a string matching a basic email format, max 254 characters.
 *
 * @param {*} value - Raw body value.
 * @param {boolean} [required=true] - Whether the field is required.
 * @returns {string[]} Array of validation error messages.
 */
function validateEmail(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (value.length > 254) {
    errors.push('email must be at most 254 characters long');
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Collect all errors from multiple validators and, if any exist,
 * send a 400 response with a structured error payload.
 *
 * Returns `true` when validation failed (response already sent),
 * `false` when everything is valid (caller should continue).
 *
 * @param {import('express').Response} res - Express response object.
 * @param {string[][]} errorArrays - Results from one or more validators.
 * @returns {boolean} Whether validation failed.
 */
function sendValidationErrors(res, errorArrays) {
  const errors = errorArrays.flat();
  if (errors.length === 0) return false;

  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = { validateId, validateName, validateEmail, sendValidationErrors };

