const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validates a numeric ID (route param or body field).
 * Accepts a raw string (from req.params) or a number.
 * Returns an error message string, or null when valid.
 */
function validateId(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

/**
 * Validates a name field.
 * Returns an array of error message strings (empty when valid).
 */
function validateName(value, fieldName = 'name', { required = true } = {}) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    if (required) errors.push(`${fieldName} is required`);
    return errors; // further checks are meaningless without a value
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`${fieldName} must be at least 1 character`);
  }
  if (trimmed.length > 100) {
    errors.push(`${fieldName} must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validates an email field.
 * Returns an array of error message strings (empty when valid).
 */
function validateEmail(value, fieldName = 'email', { required = true } = {}) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    if (required) errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`${fieldName} must be at most 254 characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }

  return errors;
}

/**
 * Validates the body of a create-user (POST) request.
 * Both `name` and `email` are required.
 */
function validateCreateUser(body) {
  const errors = [
    ...validateName(body.name, 'name', { required: true }),
    ...validateEmail(body.email, 'email', { required: true }),
  ];
  return errors;
}

/**
 * Validates the body of an update-user (PUT) request.
 * At least one of `name` or `email` must be supplied; each is validated only
 * when present so callers can do partial updates.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return errors;
  }

  if (hasName)  errors.push(...validateName (body.name,  'name',  { required: false }));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', { required: false }));

  return errors;
}

/**
 * Convenience middleware factory: validates a numeric :id route param and
 * returns a 400 response when it is invalid, otherwise calls next().
 */
function validateParamId(paramName = 'id') {
  return (req, res, next) => {
    const err = validateId(req.params[paramName], paramName);
    if (err) {
      return res.status(400).json({ errors: [err] });
    }
    next();
  };
}

/**
 * Generic helper used inside route handlers to send a 400 with the full
 * errors array when validation fails.
 *
 * Usage:
 *   const errors = validateCreateUser(req.body);
 *   if (failFast(res, errors)) return;
 */
function failFast(res, errors) {
  if (errors.length > 0) {
    res.status(400).json({ errors });
    return true;
  }
  return false;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validateParamId,
  failFast,
};

