// validation.js - Reusable input validation helpers

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

/**
 * Validates a user ID route parameter.
 * The raw string value from req.params must represent a positive integer.
 *
 * @param {string} id - Raw value from req.params.id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
  } else if (!/^\d+$/.test(String(id)) || parseInt(id, 10) <= 0) {
    errors.push('id must be a positive integer');
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validates user body fields (name and/or email).
 * Fields that are present are always type- and length-checked.
 * Fields that are absent are only flagged when marked as required.
 *
 * @param {object} body - Parsed request body (req.body)
 * @param {object} [options]
 * @param {boolean} [options.requireName=false] - Fail when name is missing
 * @param {boolean} [options.requireEmail=false] - Fail when email is missing
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserBody(body, { requireName = false, requireEmail = false } = {}) {
  const errors = [];
  const { name, email } = body || {};

  // --- name ---
  if (name === undefined || name === null) {
    if (requireName) {
      errors.push('name is required');
    }
  } else if (typeof name !== 'string') {
    errors.push('name must be a string');
  } else if (name.length < MIN_NAME_LENGTH) {
    errors.push(`name must be at least ${MIN_NAME_LENGTH} character long`);
  } else if (name.length > MAX_NAME_LENGTH) {
    errors.push(`name must be at most ${MAX_NAME_LENGTH} characters long`);
  }

  // --- email ---
  if (email === undefined || email === null) {
    if (requireEmail) {
      errors.push('email is required');
    }
  } else if (typeof email !== 'string') {
    errors.push('email must be a string');
  } else if (email.length > MAX_EMAIL_LENGTH) {
    errors.push(`email must be at most ${MAX_EMAIL_LENGTH} characters long`);
  } else if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return { valid: errors.length === 0, errors };
}

module.exports = { validateId, validateUserBody };

