/** Email regex per RFC 5321 / common practice (max local 64, domain 253). */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route parameter or query value that must be a positive integer.
 * Accepts numeric strings (e.g. "42") as well as actual numbers.
 *
 * @param {*}      value - The value to check.
 * @param {string} field - Field name used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`'${field}' is required`);
    return errors; // no point continuing
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`'${field}' must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name string.
 * Rules: required, must be a non-empty string, length 1–100 characters.
 *
 * @param {*}      value    - The value to check.
 * @param {string} field    - Field name used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateName(value, field = 'name', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`'${field}' must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`'${field}' must be at most 100 characters (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email address.
 * Rules: required, must be a string, valid email format, max 254 characters.
 *
 * @param {*}      value    - The value to check.
 * @param {string} field    - Field name used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateEmail(value, field = 'email', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`'${field}' must be at most 254 characters (got ${value.length})`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${field}' must be a valid email address`);
  }

  return errors;
}

/**
 * Validate a user request body.
 *
 * @param {object}  body          - The parsed request body.
 * @param {object}  [opts]
 * @param {boolean} [opts.requireName=true]  - Whether 'name' is mandatory.
 * @param {boolean} [opts.requireEmail=true] - Whether 'email' is mandatory.
 * @returns {string[]} Aggregated list of validation errors.
 */
function validateUserBody(body, { requireName = true, requireEmail = true } = {}) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['Request body must be a JSON object'];
  }

  return [
    ...validateName(body.name, 'name', requireName),
    ...validateEmail(body.email, 'email', requireEmail),
  ];
}

/**
 * Express middleware factory – validates `:id` route params.
 * Responds with 400 if invalid; otherwise calls next().
 */
function requireValidId(paramName = 'id') {
  return (req, res, next) => {
    const errors = validateId(req.params[paramName], paramName);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

/**
 * Build a standard 400 error response body.
 *
 * @param {string[]} errors
 * @returns {{ errors: string[] }}
 */
function badRequest(errors) {
  return { errors };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  requireValidId,
  badRequest,
};

