/**
 * Validation helper module.
 * Each validator returns an array of error message strings (empty = valid).
 * `validate()` runs multiple validators, collects all errors, and returns a
 * structured result so route handlers stay clean.
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual field validators
// ---------------------------------------------------------------------------

/**
 * Validate a route/query parameter that must be a whole-number ID.
 * Accepts a string value (as received from req.params / req.query) or a number.
 *
 * @param {*}      value - The raw value to check.
 * @param {string} [field='id'] - Field name used in error messages.
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no further checks make sense
  }

  const asNumber = Number(value);
  if (!Number.isInteger(asNumber) || asNumber <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field.
 * Must be present, a string, and 1–100 characters long.
 *
 * @param {*}      value - The raw value to check.
 * @param {string} [field='name'] - Field name used in error messages.
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors; // length checks are meaningless for non-strings
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email field.
 * Must be present, a string, match a standard email pattern, and be ≤ 254 chars.
 *
 * @param {*}      value - The raw value to check.
 * @param {string} [field='email'] - Field name used in error messages.
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  // RFC 5321 limits the total length to 254 characters.
  const MAX_EMAIL_LENGTH = 254;

  // A practical regex: local@domain.tld
  // Allows common special characters in the local part and requires at least
  // one dot in the domain portion.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > MAX_EMAIL_LENGTH) {
    errors.push(`"${field}" must be at most ${MAX_EMAIL_LENGTH} characters (got ${value.length})`);
  }

  if (!EMAIL_RE.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validator
// ---------------------------------------------------------------------------

/**
 * Run an array of validation functions and aggregate their errors.
 *
 * Usage:
 *   const result = validate([
 *     () => validateId(req.params.id),
 *     () => validateName(req.body.name),
 *     () => validateEmail(req.body.email),
 *   ]);
 *
 *   if (!result.valid) {
 *     return res.status(400).json(result);
 *   }
 *
 * @param {Array<() => string[]>} checks - Zero-arg functions that each return
 *   an array of error strings.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validate(checks) {
  const errors = checks.flatMap((fn) => fn());
  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Optional-field wrappers (skip validation when field is absent in PATCH-style
// partial updates)
// ---------------------------------------------------------------------------

/**
 * Return a validator function that only runs `validatorFn` when `value` is
 * actually present in the request body (not undefined).  Useful for partial
 * update routes where every field is optional but still must be valid if given.
 *
 * @param {*}           value       - The field value.
 * @param {Function}    validatorFn - One of the validators above (bound or arrow).
 * @returns {() => string[]}
 */
function ifPresent(value, validatorFn) {
  return () => (value !== undefined ? validatorFn() : []);
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validate,
  ifPresent,
};

// Simple application for agent to work on
