'use strict';

const express = require('express');
const { validateId, validateName, validateEmail, validate, ifPresent } = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory "database" (seeded with the original two users)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Helper: find a user by id (parsed integer)
// ---------------------------------------------------------------------------
function findUser(id) {
  return users.find((u) => u.id === id);
}

// ---------------------------------------------------------------------------
// GET /health  – no user input to validate
// ---------------------------------------------------------------------------
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users  – list all users
// ---------------------------------------------------------------------------
app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// GET /users/:id  – get a single user
// ---------------------------------------------------------------------------
app.get('/users/:id', (req, res) => {
  const result = validate([
    () => validateId(req.params.id, 'id'),
  ]);

  if (!result.valid) {
    return res.status(400).json({ message: 'Validation failed', errors: result.errors });
  }

  const id   = Number(req.params.id);
  const user = findUser(id);

  if (!user) {
    return res.status(404).json({ message: `User with id ${id} not found` });
  }

  res.json(user);
});

// ---------------------------------------------------------------------------
// POST /users  – create a new user
// ---------------------------------------------------------------------------
app.post('/users', (req, res) => {
  const { name, email } = req.body || {};

  const result = validate([
    () => validateName(name,   'name'),
    () => validateEmail(email, 'email'),
  ]);

  if (!result.valid) {
    return res.status(400).json({ message: 'Validation failed', errors: result.errors });
  }

  const newUser = { id: nextId++, name: name.trim(), email };
  users.push(newUser);
  res.status(201).json(newUser);
});

// ---------------------------------------------------------------------------
// PUT /users/:id  – full replacement of an existing user
// ---------------------------------------------------------------------------
app.put('/users/:id', (req, res) => {
  const { name, email } = req.body || {};

  const result = validate([
    () => validateId(req.params.id, 'id'),
    () => validateName(name,        'name'),
    () => validateEmail(email,      'email'),
  ]);

  if (!result.valid) {
    return res.status(400).json({ message: 'Validation failed', errors: result.errors });
  }

  const id    = Number(req.params.id);
  const index = users.findIndex((u) => u.id === id);

  if (index === -1) {
    return res.status(404).json({ message: `User with id ${id} not found` });
  }

  users[index] = { id, name: name.trim(), email };
  res.json(users[index]);
});

// ---------------------------------------------------------------------------
// PATCH /users/:id  – partial update (only supplied fields are changed)
// ---------------------------------------------------------------------------
app.patch('/users/:id', (req, res) => {
  const { name, email } = req.body || {};

  const result = validate([
    ()  => validateId(req.params.id, 'id'),
    // Only validate name / email when they are actually provided
    ifPresent(name,  () => validateName(name,   'name')),
    ifPresent(email, () => validateEmail(email, 'email')),
  ]);

  if (!result.valid) {
    return res.status(400).json({ message: 'Validation failed', errors: result.errors });
  }

  // Require at least one field to update
  if (name === undefined && email === undefined) {
    return res
      .status(400)
      .json({ message: 'Validation failed', errors: ['At least one field ("name" or "email") must be provided'] });
  }

  const id    = Number(req.params.id);
  const index = users.findIndex((u) => u.id === id);

  if (index === -1) {
    return res.status(404).json({ message: `User with id ${id} not found` });
  }

  if (name  !== undefined) users[index].name  = name.trim();
  if (email !== undefined) users[index].email = email;

  res.json(users[index]);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id  – remove a user
// ---------------------------------------------------------------------------
app.delete('/users/:id', (req, res) => {
  const result = validate([
    () => validateId(req.params.id, 'id'),
  ]);

  if (!result.valid) {
    return res.status(400).json({ message: 'Validation failed', errors: result.errors });
  }

  const id    = Number(req.params.id);
  const index = users.findIndex((u) => u.id === id);

  if (index === -1) {
    return res.status(404).json({ message: `User with id ${id} not found` });
  }

  const deleted = users.splice(index, 1)[0];
  res.json({ message: 'User deleted', user: deleted });
});

// ---------------------------------------------------------------------------
// Start
// ---------------------------------------------------------------------------
app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

